import{_ as e,c as t,o as a,d as r}from"./app.5502e05d.js";const c=JSON.parse('{"title":"Den digitala h\xE5llbarhetsplattformen Prodikt","description":"","frontmatter":{},"headers":[{"level":3,"title":"","slug":"-1"},{"level":3,"title":"","slug":"-2"}],"relativePath":"index.md"}'),n={name:"index.md"},i=r('<h1 id="den-digitala-hallbarhetsplattformen-prodikt" tabindex="-1">Den digitala h\xE5llbarhetsplattformen Prodikt <a class="header-anchor" href="#den-digitala-hallbarhetsplattformen-prodikt" aria-hidden="true">#</a></h1><p><em>Lagen om klimatdeklarationer f\xF6r byggnader b\xF6rjade g\xE4lla den 1 januari 2022. Lagen ber\xF6r nya byggnader d\xE4r bygglov s\xF6ks fr\xE5n och med det datumet, och syftet \xE4r att minska klimatp\xE5verkan fr\xE5n byggskedet. Den nya lagen inneb\xE4r att byggherren ska redovisa den klimatp\xE5verkan som uppst\xE5r under byggskedet i en s\xE5 kallad klimatdeklaration som ska registreras hos Boverket i Boverkets register f\xF6r klimatdeklarationer.</em></p><h4 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h4><p><strong>F\xF6r att kraftfullt minska koldioxidutsl\xE4ppen fr\xE5n bygg- och fastighetsbranschen finns ett stort behov av att enkelt m\xE4ta klimatp\xE5verkan fr\xE5n material som anv\xE4nds vid byggnationer. Dessutom finns det s\xE5ledes nu ocks\xE5 ett akut behov av verktyg som kan hantera och skapa klimatdeklarationer f\xF6r inregistrering hos Boverket.</strong></p><p><strong>Prodikt</strong> \u2013 en h\xE5llbarhetsplattorm f\xF6r produkter (byggmaterial och m\xF6bler) och projekt har funnits fullt tillg\xE4nglig sedan maj, 2021 och nu kommer en kraftfull och vital uppgradering som kommer att betydligt underl\xE4tta f\xF6r byggbranschens ber\xF6rda akt\xF6rer. M\xF6jligheten att klimatdeklarera kommer i samband med den st\xF6rsta uppdateringen hittills f\xF6r Prodikt, d\xE4r bland andra team-funktion och att arbeta med importerade BIM-filer finns.</p><p>Viljan av att minska klimatavtrycket fr\xE5n branschen har \xF6kat de senaste \xE5ren. Det \xE4r mycket positivt. Nu kommer det d\xE5 ett lagkrav och ett regelverk som pekar ut riktningen ocks\xE5 officiellt. D\xE5 kr\xE4vs det ett konkret och pedagogiskt verktyg. Den nyutvecklade digitala plattformen Prodikt - <a href="http://www.prodikt.com" target="_blank" rel="noopener noreferrer">www.prodikt.com</a>, g\xF6r det m\xF6jligt att p\xE5 ett enkelt s\xE4tt f\xE5 veta olika byggmaterials h\xE5llbarhetsprestanda samt att skapa en klimatdeklaration med h\xF6g kvalitet p\xE5 ett enkelt s\xE4tt.</p><h3 id="-1" tabindex="-1"><a class="header-anchor" href="#-1" aria-hidden="true">#</a></h3><p><em><strong>F\xF6rdelar med att klimatdeklarera i just Prodikt</strong></em></p><ul><li><em>Enkelt och pedagogiskt - passar b\xE5de specialisten och nyb\xF6rjaren</em></li><li><em>Helt unik informationskvalitet - m\xF6jlighet till uppf\xF6ljning och interna m\xE5lv\xE4rden</em></li><li><em>Precisa ber\xE4kningar - b\xE5de EPD*-specifika och generiska v\xE4rden</em></li><li><em>Projektanpassad - st\xF6der projektprocessen vad g\xE4ller import av till exempel kalkylfiler, BIM-modeller och Team-funktion</em></li></ul><h3 id="-2" tabindex="-1"><a class="header-anchor" href="#-2" aria-hidden="true">#</a></h3><p>Kom ig\xE5ng direkt! Ring Pierre omedelbart.</p>',11),l=[i];function o(s,d,k,m,h,g){return a(),t("div",null,l)}var f=e(n,[["render",o]]);export{c as __pageData,f as default};
